-- Complete registry coverage for accepted Layer 3 TargetStateVector V1 values.
-- Registers every contract-owned state-vector block/group, model score pattern,
-- derived model payload, and fixed enum/window value that was previously only
-- documented or grouped inside aggregate configs.

UPDATE trading_registry
SET path = 'trading-model/src/models/model_03_target_state_vector/target_state_vector_contract.md',
    applies_to = CASE
      WHEN applies_to LIKE '%sector_state_features%' THEN applies_to
      ELSE COALESCE(applies_to || ';', '') || 'sector_state_features;target_state_vector;model_03_target_state_vector;feature_03_target_state_vector;target_state_vector_model'
    END,
    note = 'Conceptual Layer 2 sector_context_state and Layer 3 sector-state feature group carried inside TargetStateVector rows. It remains direction-neutral sector context and must not become final target/action selection.',
    updated_at = CURRENT_TIMESTAMP
WHERE key = 'SECTOR_CONTEXT_STATE';

ON CONFLICT (id) DO UPDATE SET
    kind = EXCLUDED.kind,
    key = EXCLUDED.key,
    payload_format = EXCLUDED.payload_format,
    payload = EXCLUDED.payload,
    path = EXCLUDED.path,
    applies_to = EXCLUDED.applies_to,
    artifact_sync_policy = EXCLUDED.artifact_sync_policy,
    note = EXCLUDED.note,
    updated_at = CURRENT_TIMESTAMP;
